import { useState } from "react";
import Sidebar from "./Sidebar";

export default function MaterialExpenseManagement() {

  const today = new Date().toISOString().split("T")[0];

  // UI STATE
  const [activeForm, setActiveForm] = useState(""); // "material" | "expense" | ""
  const [materials, setMaterials] = useState([]);
  const [expenses, setExpenses] = useState([]);

  // MATERIAL FORM
  const [materialForm, setMaterialForm] = useState({
    name: "",
    category: "",
    quantity: "",
    unit: "",
    price: "",
    gst: "",
    supplier: "",
    contact: "",
    date: today,
    invoice: "",
    project: "",
    site: "",
    usedQty: 0,
    minStock: 0
  });

  // EXPENSE FORM
  const [expenseForm, setExpenseForm] = useState({
    title: "",
    category: "",
    amount: "",
    date: today,
    paymentMethod: "Cash",
    status: "Paid",
    project: "",
    approvedBy: "",
    description: ""
  });

  // ================= MATERIAL HANDLER =================
  const handleMaterialChange = (e) => {
    const { name, value } = e.target;
    setMaterialForm({ ...materialForm, [name]: value });
  };

  const addMaterial = (e) => {
    e.preventDefault();

    const qty = Number(materialForm.quantity);
    const price = Number(materialForm.price);
    const gst = Number(materialForm.gst || 0);

    const total = qty * price;
    const final = total + (total * gst) / 100;

    const remaining = qty - Number(materialForm.usedQty || 0);

    const newMaterial = {
      ...materialForm,
      totalCost: total,
      finalCost: final,
      remainingStock: remaining
    };

    setMaterials([...materials, newMaterial]);
    setActiveForm("");
  };

  // ================= EXPENSE HANDLER =================
  const handleExpenseChange = (e) => {
    setExpenseForm({ ...expenseForm, [e.target.name]: e.target.value });
  };

  const addExpense = (e) => {
    e.preventDefault();

    const newExpense = {
      ...expenseForm,
      amount: Number(expenseForm.amount)
    };

    setExpenses([...expenses, newExpense]);
    setActiveForm("");
  };

  // ================= DASHBOARD CALCULATIONS =================
  const totalMaterialCost = materials.reduce((a, b) => a + (b.finalCost || 0), 0);
  const totalExpenseCost = expenses.reduce((a, b) => a + (b.amount || 0), 0);

  const lowStock = materials.filter(m => Number(m.remainingStock) < Number(m.minStock));

  return (
    <div className="flex bg-gray-100 min-h-screen">

      <Sidebar />

      <div className="flex-1 p-8">

        {/* ================= DASHBOARD ================= */}
        {activeForm === "" && (
          <>
            <h1 className="text-3xl font-bold mb-6">
              Material & Expense Dashboard
            </h1>

            <div className="grid grid-cols-3 gap-6 mb-8">

              <div className="bg-white p-6 rounded shadow">
                <p>Total Materials Cost</p>
                <h2 className="text-xl font-bold">₹{totalMaterialCost}</h2>
              </div>

              <div className="bg-white p-6 rounded shadow">
                <p>Total Expenses</p>
                <h2 className="text-xl font-bold">₹{totalExpenseCost}</h2>
              </div>

              <div className="bg-white p-6 rounded shadow">
                <p>Low Stock Items</p>
                <h2 className="text-xl font-bold">{lowStock.length}</h2>
              </div>

            </div>

            <div className="flex gap-4">
              <button
                onClick={() => setActiveForm("material")}
                className="bg-orange-500 text-white px-5 py-2 rounded"
              >
                + Material Form
              </button>

              <button
                onClick={() => setActiveForm("expense")}
                className="bg-blue-500 text-white px-5 py-2 rounded"
              >
                + Expense Form
              </button>
            </div>
          </>
        )}

        {/* ================= MATERIAL FORM ================= */}
        {activeForm === "material" && (
          <div className="bg-white p-6 mt-6 rounded shadow">
            <h2 className="text-xl font-bold mb-4">Material Form</h2>

            <form onSubmit={addMaterial} className="grid grid-cols-3 gap-4">

              <input name="name" placeholder="Material Name" onChange={handleMaterialChange} className="border p-2 rounded" />
              <input name="category" placeholder="Category" onChange={handleMaterialChange} className="border p-2 rounded" />
              <input name="quantity" type="number" placeholder="Quantity" onChange={handleMaterialChange} className="border p-2 rounded" />
              <input name="unit" placeholder="Unit" onChange={handleMaterialChange} className="border p-2 rounded" />
              <input name="price" type="number" placeholder="Price" onChange={handleMaterialChange} className="border p-2 rounded" />
              <input name="gst" type="number" placeholder="GST %" onChange={handleMaterialChange} className="border p-2 rounded" />

              <input name="supplier" placeholder="Supplier" onChange={handleMaterialChange} className="border p-2 rounded" />
              <input name="contact" placeholder="Contact" onChange={handleMaterialChange} className="border p-2 rounded" />
              <input type="date" name="date" value={materialForm.date} onChange={handleMaterialChange} className="border p-2 rounded" />

              <button className="bg-green-500 text-white px-4 py-2 rounded col-span-3">
                Save Material
              </button>

            </form>

            <button onClick={() => setActiveForm("")} className="mt-4 underline">
              Back
            </button>
          </div>
        )}

        {/* ================= EXPENSE FORM ================= */}
        {activeForm === "expense" && (
          <div className="bg-white p-6 mt-6 rounded shadow">
            <h2 className="text-xl font-bold mb-4">Expense Form</h2>

            <form onSubmit={addExpense} className="grid grid-cols-3 gap-4">

              <input name="title" placeholder="Expense Title" onChange={handleExpenseChange} className="border p-2 rounded" />

              <select name="category" onChange={handleExpenseChange} className="border p-2 rounded">
                <option>Material Cost</option>
                <option>Labor</option>
                <option>Transport</option>
                <option>Electricity</option>
                <option>Equipment</option>
              </select>

              <input name="amount" type="number" placeholder="Amount" onChange={handleExpenseChange} className="border p-2 rounded" />

              <select name="paymentMethod" onChange={handleExpenseChange} className="border p-2 rounded">
                <option>Cash</option>
                <option>UPI</option>
                <option>Bank</option>
              </select>

              <input type="date" name="date" value={expenseForm.date} onChange={handleExpenseChange} className="border p-2 rounded" />

              <input name="approvedBy" placeholder="Approved By" onChange={handleExpenseChange} className="border p-2 rounded" />

              <textarea name="description" placeholder="Notes" onChange={handleExpenseChange} className="border p-2 rounded col-span-3" />

              <button className="bg-blue-500 text-white px-4 py-2 rounded col-span-3">
                Save Expense
              </button>

            </form>

            <button onClick={() => setActiveForm("")} className="mt-4 underline">
              Back
            </button>
          </div>
        )}

      </div>
    </div>
  );
}
